'use client';

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import { usePathname } from 'next/navigation';
import { Search, ShoppingBag, User, Menu, X, ChevronDown, Package, ChevronRight } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useCart } from '@/context/CartContext';
import { MAIN_CATEGORIES } from '@/lib/products';
import SearchModal from './SearchModal';
import { useDictionary } from '@/context/DictionaryContext';
import LanguageSwitcher from './LanguageSwitcher';

export default function Header() {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [activeMenu, setActiveMenu] = useState<'women' | 'men' | 'unisex' | 'brands' | null>(null);
  const { getItemCount } = useCart();
  const pathname = usePathname();
  const dict = useDictionary();
  const cartCount = getItemCount();

  const locale = pathname?.split('/')[1] || 'fr';
  const isHome = pathname === `/${locale}`;

  const [brands, setBrands] = useState<any[]>([]);
  useEffect(() => {
    fetch('/api/brands')
      .then(res => res.json())
      .then(data => setBrands(data))
      .catch(console.error);
  }, []);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 30);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Determine if header should be solid white
  const isSolid = !isHome || isScrolled || activeMenu !== null || isMobileMenuOpen;

  return (
    <>
      <header
        onMouseLeave={() => setActiveMenu(null)}
        className={`fixed top-0 left-0 w-full z-50 transition-all duration-300 ${
          isSolid ? 'bg-white shadow-sm border-b border-[#e0ddd4]' : 'bg-transparent'
        }`}
      >
        {/* TOP BAR */}
        <div className="hidden lg:block bg-[#1A1A1A] text-white py-1.5 px-6 text-center text-[10px] font-bold tracking-[0.2em] uppercase">
          Livraison offerte partout au Maroc dès 1000 Dh d'achats
        </div>

        <div className="max-w-[1600px] mx-auto px-6 lg:px-10">
          <div className="flex items-center justify-between h-[60px] lg:h-[75px]">
            {/* LEFT NAV (Desktop) */}
            <nav className="hidden lg:flex items-center gap-8 w-1/3">
              {['women', 'men', 'unisex', 'brands'].map((menuKey) => {
                const labels: any = { women: 'Femme', men: 'Homme', unisex: 'Coffrets', brands: 'Marques' };
                return (
                  <div 
                    key={menuKey} 
                    className="h-full flex items-center"
                    onMouseEnter={() => setActiveMenu(menuKey as any)}
                  >
                    <button
                      className={`text-[11px] font-bold tracking-[0.15em] uppercase transition-colors duration-300 flex items-center gap-1.5 h-[75px] border-b-2 ${
                        activeMenu === menuKey ? 'border-[#0ea5e9] text-[#0ea5e9]' : 'border-transparent ' + (isSolid ? 'text-[#1A1A1A]' : 'text-white hover:text-white/80')
                      }`}
                    >
                      {labels[menuKey]}
                    </button>
                  </div>
                );
              })}
            </nav>

            {/* LOGO */}
            <div className="w-1/3 flex justify-center">
              <Link href={`/${locale}`} className="group flex flex-col items-center">
                <span
                  className={`heading-font text-[24px] lg:text-[28px] font-light tracking-[0.25em] transition-colors duration-300 group-hover:text-[#0ea5e9] ${
                    isSolid ? 'text-[#1A1A1A]' : 'text-white'
                  }`}
                >
                  NOUAMANE
                </span>
                <span
                  className={`text-[8px] font-semibold tracking-[0.35em] uppercase mt-[-2px] ${
                    isSolid ? 'text-[#0ea5e9]' : 'text-white/80'
                  }`}
                >
                  Parfums
                </span>
              </Link>
            </div>

            {/* RIGHT ICONS */}
            <div className="w-1/3 flex items-center justify-end gap-5 lg:gap-6">
              <button
                onClick={() => setIsSearchOpen(true)}
                className={`hidden lg:block transition-colors duration-300 ${
                  isSolid ? 'text-[#1A1A1A] hover:text-[#0ea5e9]' : 'text-white hover:text-white/80'
                }`}
                aria-label="Recherche"
              >
                <Search className="w-[18px] h-[18px]" strokeWidth={1.5} />
              </button>

              <Link
                href="/cart"
                className={`transition-colors duration-300 relative ${
                  isSolid ? 'text-[#1A1A1A] hover:text-[#0ea5e9]' : 'text-white hover:text-white/80'
                }`}
                aria-label="Panier"
              >
                <ShoppingBag className="w-[18px] h-[18px]" strokeWidth={1.5} />
                {cartCount > 0 && (
                  <span className="absolute -top-1.5 -right-2 bg-[#0ea5e9] text-white text-[9px] font-bold w-[16px] h-[16px] flex items-center justify-center rounded-full leading-none">
                    {cartCount}
                  </span>
                )}
              </Link>

              <Link
                href="/suivi-commande"
                className={`hidden lg:block transition-colors duration-300 ${
                  isSolid ? 'text-[#1A1A1A] hover:text-[#0ea5e9]' : 'text-white hover:text-white/80'
                }`}
                aria-label="Compte"
              >
                <User className="w-[18px] h-[18px]" strokeWidth={1.5} />
              </Link>

              <div className="hidden lg:block">
                <LanguageSwitcher />
              </div>

              <button
                onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
                className={`lg:hidden ${isSolid ? 'text-[#1A1A1A]' : 'text-white'}`}
                aria-label="Menu"
              >
                {isMobileMenuOpen ? <X size={24} strokeWidth={1.5} /> : <Menu size={24} strokeWidth={1.5} />}
              </button>
            </div>
          </div>
        </div>

        {/* ============================================================== */}
        {/* MEGA MENUS DESKTOP */}
        {/* ============================================================== */}
        <AnimatePresence>
          {activeMenu && (
            <motion.div
              initial={{ opacity: 0, y: -5 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -5 }}
              transition={{ duration: 0.2 }}
              className="hidden lg:block absolute top-[106px] lg:top-[99px] left-0 right-0 bg-white shadow-2xl border-t border-[#e0ddd4] overflow-hidden"
              style={{ maxHeight: '70vh' }}
            >
              <div className="max-w-[1400px] mx-auto px-10 py-12 flex gap-16">

                {/* --- WOMEN MEGA MENU --- */}
                {activeMenu === 'women' && (
                  <>
                    <div className="flex-1 grid grid-cols-3 gap-12">
                      <div>
                        <div className="text-[10px] font-bold tracking-[0.2em] uppercase text-[#9A9A9A] mb-5">Familles Olfactives</div>
                        <ul className="space-y-4">
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/women?sub=floral" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Parfums Floraux</Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/women?sub=oriental" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Parfums Orientaux</Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/women?sub=woody" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Parfums Boisés</Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/women?sub=fresh" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Parfums Frais</Link></li>
                          <li className="pt-2"><Link onClick={() => setActiveMenu(null)} href="/shop/women" className="text-[11px] font-bold uppercase tracking-wider text-[#0ea5e9] flex items-center gap-1">Tout voir <ChevronRight size={14}/></Link></li>
                        </ul>
                      </div>
                      <div>
                        <div className="text-[10px] font-bold tracking-[0.2em] uppercase text-[#9A9A9A] mb-5">Découverte</div>
                        <ul className="space-y-4">
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/women" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors flex items-center gap-2">Testeurs Originaux <span className="bg-[#ecfdf5] text-[#10b981] px-1.5 py-0.5 rounded text-[9px] font-bold uppercase tracking-wider">Nouveau</span></Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/women" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Meilleures Ventes</Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/women" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Nouveautés</Link></li>
                        </ul>
                      </div>
                      <div>
                        <div className="text-[10px] font-bold tracking-[0.2em] uppercase text-[#9A9A9A] mb-5">Marques Phares</div>
                        <ul className="space-y-4">
                          <li><Link onClick={() => setActiveMenu(null)} href="/brands/yves-saint-laurent" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Yves Saint Laurent</Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/brands/valentino" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Valentino</Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/brands/armani" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Giorgio Armani</Link></li>
                        </ul>
                      </div>
                    </div>
                    <div className="w-[380px] shrink-0 border-l border-[#e0ddd4] pl-16">
                      <Link href="/product/ysl-libre-edp" onClick={() => setActiveMenu(null)} className="group block">
                        <div className="relative aspect-[4/3] rounded-lg overflow-hidden bg-[#f8fafc] mb-4">
                          <Image src="https://images.pexels.com/photos/11216321/pexels-photo-11216321.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=600&w=800" alt="YSL Libre" fill className="object-cover group-hover:scale-105 transition-transform duration-700" />
                        </div>
                        <div className="text-[9px] font-bold tracking-[0.25em] uppercase text-[#0ea5e9] mb-1">Parfum du Moment</div>
                        <div className="heading-font text-xl text-[#1A1A1A] group-hover:text-[#0ea5e9] transition-colors">YSL Libre Eau de Parfum</div>
                      </Link>
                    </div>
                  </>
                )}

                {/* --- MEN MEGA MENU --- */}
                {activeMenu === 'men' && (
                  <>
                    <div className="flex-1 grid grid-cols-3 gap-12">
                      <div>
                        <div className="text-[10px] font-bold tracking-[0.2em] uppercase text-[#9A9A9A] mb-5">Familles Olfactives</div>
                        <ul className="space-y-4">
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/men?sub=woody" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Parfums Boisés</Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/men?sub=oriental" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Parfums Orientaux</Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/men?sub=aromatic" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Parfums Aromatiques</Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/men?sub=fresh" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Parfums Frais</Link></li>
                          <li className="pt-2"><Link onClick={() => setActiveMenu(null)} href="/shop/men" className="text-[11px] font-bold uppercase tracking-wider text-[#0ea5e9] flex items-center gap-1">Tout voir <ChevronRight size={14}/></Link></li>
                        </ul>
                      </div>
                      <div>
                        <div className="text-[10px] font-bold tracking-[0.2em] uppercase text-[#9A9A9A] mb-5">Découverte</div>
                        <ul className="space-y-4">
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/men" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors flex items-center gap-2">Testeurs Originaux <span className="bg-[#ecfdf5] text-[#10b981] px-1.5 py-0.5 rounded text-[9px] font-bold uppercase tracking-wider">Nouveau</span></Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/men" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Meilleures Ventes</Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/men" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Nouveautés</Link></li>
                        </ul>
                      </div>
                      <div>
                        <div className="text-[10px] font-bold tracking-[0.2em] uppercase text-[#9A9A9A] mb-5">Marques Phares</div>
                        <ul className="space-y-4">
                          <li><Link onClick={() => setActiveMenu(null)} href="/brands/armani" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Giorgio Armani</Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/brands/yves-saint-laurent" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Yves Saint Laurent</Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/brands/valentino" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Valentino</Link></li>
                        </ul>
                      </div>
                    </div>
                    <div className="w-[380px] shrink-0 border-l border-[#e0ddd4] pl-16">
                      <Link href="/product/armani-acqua-di-gio-profumo" onClick={() => setActiveMenu(null)} className="group block">
                        <div className="relative aspect-[4/3] rounded-lg overflow-hidden bg-[#f8fafc] mb-4">
                          <Image src="https://images.pexels.com/photos/31771395/pexels-photo-31771395.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=600&w=800" alt="Acqua di Giò" fill className="object-cover group-hover:scale-105 transition-transform duration-700" />
                        </div>
                        <div className="text-[9px] font-bold tracking-[0.25em] uppercase text-[#0ea5e9] mb-1">Incontournable Homme</div>
                        <div className="heading-font text-xl text-[#1A1A1A] group-hover:text-[#0ea5e9] transition-colors">Acqua di Giò Profumo</div>
                      </Link>
                    </div>
                  </>
                )}

                {/* --- UNISEX & COFFRETS MEGA MENU --- */}
                {activeMenu === 'unisex' && (
                  <>
                    <div className="flex-1 grid grid-cols-2 gap-12">
                      <div>
                        <div className="text-[10px] font-bold tracking-[0.2em] uppercase text-[#9A9A9A] mb-5">Idées Cadeaux</div>
                        <ul className="space-y-4">
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/unisex?sub=gift-bundles" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Coffrets Cadeaux</Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/unisex?sub=discovery-sets" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Coffrets Découverte</Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/unisex?sub=limited-editions" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Éditions Limitées</Link></li>
                          <li className="pt-2"><Link onClick={() => setActiveMenu(null)} href="/shop/unisex" className="text-[11px] font-bold uppercase tracking-wider text-[#0ea5e9] flex items-center gap-1">Tout voir <ChevronRight size={14}/></Link></li>
                        </ul>
                      </div>
                      <div>
                        <div className="text-[10px] font-bold tracking-[0.2em] uppercase text-[#9A9A9A] mb-5">Parfums de niche / Unisexe</div>
                        <ul className="space-y-4">
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/unisex" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Collection Privée Armani</Link></li>
                          <li><Link onClick={() => setActiveMenu(null)} href="/shop/unisex" className="text-[13px] text-[#1A1A1A] hover:text-[#0ea5e9] transition-colors">Le Vestiaire des Parfums YSL</Link></li>
                        </ul>
                      </div>
                    </div>
                    <div className="w-[380px] shrink-0 border-l border-[#e0ddd4] pl-16">
                      <Link href="/shop/unisex" onClick={() => setActiveMenu(null)} className="group block">
                        <div className="relative aspect-[4/3] rounded-lg overflow-hidden bg-[#f8fafc] mb-4">
                          <Image src="https://images.pexels.com/photos/29986521/pexels-photo-29986521.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=600&w=800" alt="Coffrets Cadeaux" fill className="object-cover group-hover:scale-105 transition-transform duration-700" />
                        </div>
                        <div className="text-[9px] font-bold tracking-[0.25em] uppercase text-[#0ea5e9] mb-1">L'art d'offrir</div>
                        <div className="heading-font text-xl text-[#1A1A1A] group-hover:text-[#0ea5e9] transition-colors">Découvrez nos Coffrets Cadeaux</div>
                      </Link>
                    </div>
                  </>
                )}

                {/* --- BRANDS MEGA MENU --- */}
                {activeMenu === 'brands' && (
                  <div className="w-full">
                    <div className="text-[10px] font-bold tracking-[0.2em] uppercase text-[#9A9A9A] mb-6">Toutes Nos Maisons</div>
                    <div className="grid grid-cols-4 gap-6">
                      {brands.map((brand) => (
                        <Link
                          key={brand.slug}
                          href={`/brands/${brand.slug}`}
                          onClick={() => setActiveMenu(null)}
                          className="group border border-[#e0ddd4] rounded-xl overflow-hidden hover:border-[#0ea5e9] transition-colors"
                        >
                          <div className="relative h-24 bg-[#f8fafc]">
                            {brand.heroImage && (
                              <Image src={brand.heroImage} alt={brand.name} fill className="object-cover opacity-80 group-hover:opacity-100 transition-opacity" />
                            )}
                            <div className="absolute inset-0 bg-black/20 group-hover:bg-black/10 transition-colors" />
                            <div className="absolute inset-0 flex items-center justify-center">
                               <span className="text-white heading-font text-xl tracking-wider px-4 text-center">{brand.label}</span>
                            </div>
                          </div>
                          <div className="p-4 bg-white flex justify-between items-center">
                            <span className="text-[11px] font-semibold uppercase tracking-wider text-[#1A1A1A] group-hover:text-[#0ea5e9] transition-colors">Découvrir</span>
                            <ChevronRight size={14} className="text-[#9A9A9A] group-hover:text-[#0ea5e9] transition-colors" />
                          </div>
                        </Link>
                      ))}
                    </div>
                  </div>
                )}

              </div>
            </motion.div>
          )}
        </AnimatePresence>

        {/* MOBILE MENU */}
        <AnimatePresence>
          {isMobileMenuOpen && (
            <motion.div 
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              exit={{ opacity: 0, height: 0 }}
              className="lg:hidden bg-white border-t border-[#e0ddd4] overflow-y-auto"
              style={{ maxHeight: 'calc(100vh - 60px)' }}
            >
              <div className="px-6 py-8 space-y-8">
                {/* Mobile Categories */}
                <div className="space-y-6">
                  {MAIN_CATEGORIES.map((cat) => (
                    <div key={cat.slug} className="border-b border-[#e0ddd4] pb-6 last:border-0 last:pb-0">
                      <Link 
                        href={`/shop/${cat.slug}`} 
                        onClick={() => setIsMobileMenuOpen(false)}
                        className="heading-font text-2xl text-[#1A1A1A] block mb-4"
                      >
                        {cat.label}
                      </Link>
                      <div className="grid grid-cols-2 gap-3 pl-2">
                        {cat.subcategories.map(sub => (
                          <Link 
                            key={sub.slug}
                            href={`/shop/${cat.slug}?sub=${sub.slug}`}
                            onClick={() => setIsMobileMenuOpen(false)}
                            className="text-[14px] text-[#6B6B6B]"
                          >
                            {sub.label}
                          </Link>
                        ))}
                      </div>
                    </div>
                  ))}
                  <div className="border-b border-[#e0ddd4] pb-6">
                    <div className="heading-font text-2xl text-[#1A1A1A] block mb-4">Marques</div>
                    <div className="grid grid-cols-1 gap-4 pl-2">
                      {brands.map(brand => (
                        <Link 
                          key={brand.slug}
                          href={`/brands/${brand.slug}`}
                          onClick={() => setIsMobileMenuOpen(false)}
                          className="text-[15px] text-[#6B6B6B] flex items-center justify-between"
                        >
                          {brand.label} <ChevronRight size={16} className="text-[#e0ddd4]" />
                        </Link>
                      ))}
                    </div>
                  </div>
                </div>

                {/* Mobile Footer Nav */}
                <div className="pt-6 border-t border-[#e0ddd4] flex flex-col gap-5">
                  <Link
                    href="/suivi-commande"
                    onClick={() => setIsMobileMenuOpen(false)}
                    className="flex items-center gap-3 text-[15px] font-medium text-[#1A1A1A]"
                  >
                    <Package className="w-5 h-5 text-[#6B6B6B]" /> Suivi de commande
                  </Link>
                  <Link
                    href="/suivi-commande"
                    onClick={() => setIsMobileMenuOpen(false)}
                    className="flex items-center gap-3 text-[15px] font-medium text-[#1A1A1A]"
                  >
                    <User className="w-5 h-5 text-[#6B6B6B]" /> Mon Compte
                  </Link>
                  <Link
                    href="/cart"
                    onClick={() => setIsMobileMenuOpen(false)}
                    className="flex items-center gap-3 text-[15px] font-medium text-[#1A1A1A]"
                  >
                    <ShoppingBag className="w-5 h-5 text-[#6B6B6B]" /> Mon Panier ({cartCount})
                  </Link>
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>

      </header>

      {/* SEARCH MODAL */}
      <SearchModal isOpen={isSearchOpen} onClose={() => setIsSearchOpen(false)} />
    </>
  );
}
